// ei1333's BIT

struct BIT {

  VI data;



  BIT(ll sz) {

    data.assign(++sz, 0);

  }



  ll sum(ll k) {

    ll ret = 0;

    for(++k; k > 0; k -= k & -k) ret += data[k];

    return (ret);

  }



  // [i, j]

  ll range_sum(ll i, ll j){

    if(i==0){

      return sum(j);

    }else{

      return sum(j) - sum(i-1);    

    }

  }



  void add(ll k, ll x) {

    for(++k; k < data.size(); k += k & -k) data[k] += x;

  }

};



