    while(idx>0)

    {

        sum+=tree[idx];

        idx -= (idx & -idx);

    }

    return sum;

}



//Update

void update(int idx,int val)

{

    while(idx<=n)

    {

        tree[idx]+=val;

        idx += (idx & -idx);

    }

}



int main()

{

