  void build(){

    ord.resize(l.size());

    iota(ALL(ord),0);

    sort(ALL(ord),[&](int a,int b){

      if(l[a]/wid != l[b]/wid)return l[a] < l[b];

      if(r[a] == r[b])return l[a] < l[b];

      return bool((r[a] < r[b])^((l[a]/wid) & 1));

    });

  }

  inline int process(){

    if(ptr == (int)ord.size())return -1;

    const int idx = ord[ptr++];

    while(nl > l[idx])expandL(--nl);

    while(nr < r[idx])expandR(nr++);

    while(nl < l[idx])shrinkL(nl++);

    while(nr > r[idx])shrinkR(--nr);

    return idx;

  }

};





int main(){



  cin.tie(0);

  ios::sync_with_stdio(0);

  int n,Q;

  cin >> n >> Q;

  vector<int> v(n);

  rep(i,n)cin >> v[i];

  int sum = 0;

  vector<int> cnt(n+1);

  auto expand = [&](int k){

    sum += cnt[v[k]]++==0;

  };

  auto shrink = [&](int k){

    sum-=--cnt[v[k]]==0;

  };

  Mo mo(n,1000,expand,shrink);

  rep(_,Q){

    int a,b;cin >> a >> b;

    mo.add(--a,b);

  }

  vector<int> res(Q);

  mo.build();

  rep(_,Q){

    int idx = mo.process();

    res[idx] = sum;

  }

  rep(i,Q)cout << res[i] << "\n";







  return 0;

}
